import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { JournalLedgerRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-nhat-ky-chung-tu';
const PAGE_ID = 'baocao-nhat-ky-chung-tu';

const NhatKyChungTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [rows, setRows] = useState<JournalLedgerRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getJournalLedger({ fromDate, toDate })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
      />
    ),
    [fromDate, toDate, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Nhật ký chứng từ"
      titleIconClass="fas fa-book"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/accounting/journal-ledger/export-excel"
      exportParams={{ fromDate, toDate }}
      exportFilename={`NKC-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Ngày</th>
            <th>Số CT</th>
            <th>Loại</th>
            <th>Đối tác</th>
            <th className={reportStyles.colRight}>Số tiền</th>
            <th>TT</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={r.id ?? i}>
              <td>{formatDate(r.voucherDate)}</td>
              <td>{r.voucherNumber}</td>
              <td>{r.voucherType}</td>
              <td>{r.partnerName ?? '—'}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.totalAmount)}</td>
              <td>{r.status}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default NhatKyChungTuPage;
